(function(){
  const pProjects = document.getElementById('page-projects');
  const pRecipients = document.getElementById('page-recipients');
  const pickProjects = document.getElementById('pickProjects');
  const pickRecipients = document.getElementById('pickRecipients');
  pickProjects.addEventListener('click', () => {
    pProjects.style.display = ''; pRecipients.style.display = 'none';
    pickProjects.classList.add('active'); pickRecipients.classList.remove('active');
  });
  pickRecipients.addEventListener('click', () => {
    pProjects.style.display = 'none'; pRecipients.style.display = '';
    pickRecipients.classList.add('active'); pickProjects.classList.remove('active');
  });
})();

